import java.io.File;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.Arrays;
import java.util.Scanner;

public class Prinel {


	static class Task {
		public final String Input_file = "prinel.in";
		public final String Output_file = "prinel.out";

		int n, k;
		int[] target;
		int[] points;



		public void solve() {
			readInput();
			writeOutput(getResult(n));
		}

		private void readInput() {
			try {
				Scanner sc = new Scanner(new File(Input_file));
				n = sc.nextInt();
				k = sc.nextInt();
				target = new int[n];
				points = new int[n];
				for (int i = 0; i < n; i++) {
					target[i] = sc.nextInt();
				}
				for (int i = 0; i < n; i++) {
					points[i] = sc.nextInt();
				}
				sc.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		private void writeOutput(int answer) {
			try {
				PrintWriter pw = new PrintWriter(new File(Output_file));
				pw.printf("%d\n", answer);
				pw.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}


		private int rucsac(int n , int W, int[] w, int[] p) {

			// dp este o matrice de dimensiune (n + 1) x (W + 1)
			// pentru că folosim dp[0][*] pentru mulțimea vidă
			int[][] dp = new int[n + 1][W + 1];
			// cazul de bază
			for (int cap = 0; cap <= W; ++cap) {
				dp[0][cap] = 0;
			}
			for (int i = 1; i <= n; ++i) {
				for (int cap = 0; cap <= W; ++cap) {
					// nu folosesc obiectul i => e soluția de la pasul i - 1
					if (w[i - 1] > cap) {
						dp[i][cap] = dp[i - 1][cap];
					} else {
						dp[i][cap] = Math.max(dp[i - 1][cap], dp[i - 1][cap - w[i - 1]] + p[i - 1]);
					}
				}
			}
			return dp[n][W];
		}


		private int getResult(int n) {
			int[] dp = new int[10000000];
			dp[0] = 0;
			dp[1] = 0;
			dp[2] = 1;
			int maximum = Arrays.stream(target).max().getAsInt();
			//initializez dp cu nr maxim de transformari
			for (int i = 3; i <= maximum; i++) {
				dp[i] = i;
			}

			for (int i = 2; i <= maximum; i++) {
				for (int j = 1; j <= Math.sqrt(i); j++) {
					if (i % j == 0) {
						int div = j;
						if (i + div < 100000) {
							dp[i + div] = Math.min(dp[i + div], dp[i] + 1);
						}
						if (i + i / div < 100000) {
							dp[i + i / div] = Math.min(dp[i + i / div], dp[i] + 1);
						}
					}
				}
			}
			int[] res_array = new int[n];
			for (int i = 0; i < n; i++) {
				//pun doar elementele cerute in target
				//nu toate din dp
				res_array[i] = dp[target[i]];
			}
			if (Arrays.stream(res_array).sum() < k) {
				int sum = 0;
				for (int i = 0; i < n; i++) {
					sum = sum + points[i];
				}
				return sum;
			}


			return rucsac(n, k, res_array,
				points);
		}
	}

	public static void main(String[] args) {
		new Task().solve();
	}
}

