using namespace std;

using std::cout; using std::cerr;
using std::endl; using std::string;
using std::ifstream; using std::vector;

vector<int> ops(100000);

int get_ops_number(int n) {
	int result = n;
	int current_ops = 0;

	if (n == 1) {
		return 0;
	}

	if (ops.at(n) != 0) {
		return ops.at(n);
	}

    // se calculeaza numarul de operatii pentru diferentele dintre
    // numar si toti divizorii sai si se alege minimul
	for (int i = 1; i * i <= n; ++i) {
		if (n % i == 0) {
			current_ops =  get_ops_number(n - i) + 1;
			if (current_ops < result) {
				result = current_ops;
			}

			if (n / i != i && n / i != n) {
				current_ops =  get_ops_number(n - n / i) + 1;
				if (current_ops < result) {
					result = current_ops;
				}
			}
		}
	}

	ops.at(n) = result;
	return result;
}

